<template>
  <el-dialog
    title="新增經銷商"
    :visible.sync="visible"
    width="35%"
    :close-on-click-modal="false"
    :show-close="false"
    class="cus-dialog-css"
  >
    <el-form
      ref="form"
      :model="form"
      label-width="100px"
      :rules="rules"
    >
      <el-form-item
        label="企業名稱"
        prop="username"
      >
        <el-input
          v-model="form.username"
          class="input-m"
          placeholder="請輸入"
        />
      </el-form-item>
      <el-form-item
        label="聯絡人"
        prop="contact"
      >
        <el-input
          v-model="form.contact"
          class="input-m"
          placeholder="請輸入"
        />
      </el-form-item>
      <el-form-item
        label="手機號碼"
        prop="mobile"
      >
        <el-input
          v-model="form.mobile"
          class="input-m"
          :maxlength="11"
          placeholder="請輸入"
        />
      </el-form-item>
      <el-form-item
        label="登錄帳號"
        prop="login_name"
      >
        <el-input
          v-model="form.login_name"
          class="input-m"
          placeholder="請輸入"
        />
      </el-form-item>
      <el-form-item
        label="默認密碼"
        prop="password"
      >
        <el-input
          v-model="form.password"
          class="input-m"
          placeholder="請輸入"
        />
      </el-form-item>
      <el-form-item>
        <el-button
          type="primary"
          @click="handleModalConfirm(true)"
        >
          確認
        </el-button>
        <el-button
          type="primary"
          plain
          @click="handleModalConfirm(false)"
        >
          取消
        </el-button>
      </el-form-item>
    </el-form>
  </el-dialog>
</template>

<script>
import { addDealer } from '@/api/marketing'
export default {
  props: ['handleClose', 'visible'],
  data () {
    return {
      form: {
        username: '',
        contact: '',
        mobile: '',
        login_name: '',
        password: ''
      },
      rules: {
        username: [{ required: true, message: '請輸入', trigger: 'change' }],
        contact: [{ required: true, message: '請輸入', trigger: 'change' }],
        mobile: [{ required: true, message: '請輸入', trigger: 'change' }],
        login_name: [{ required: true, message: '請輸入', trigger: 'change' }],
        password: [
          { required: true, message: '請輸入', trigger: 'change', validator: this.validateNumber }
        ]
      }
    }
  },
  methods: {
    handleModalConfirm (visible) {
      if (visible) {
        this.$refs['form'].validate(async (vaild) => {
          if (vaild) {
            const { form } = this
            addDealer({ ...form, operator_type: 'dealer' })
              .then(() => {
                this.$message.success('新增成功')
                this.$emit('handleClose', false)
              })
              .catch(() => {
                this.$message.error('新增失敗')
              })
          }
        })
      } else {
        this.$emit('handleClose', false)
      }
    },
    validateNumber (rule, value, callback) {
      if (value.length < 6 || value.length > 12) {
        callback(new Error('請輸入6-12位密碼'))
      } else {
        callback()
      }
    }
  }
}
</script>
<style lang="scss">
.cus-dialog-css {
  .el-dialog__body {
    display: flex;
    justify-content: center;
  }
}
</style>
